document.addEventListener("DOMContentLoaded",function(){const t=document.querySelectorAll(".coffer-platform-tab"),e=document.querySelectorAll(".coffer-tab-pane");t.forEach(function(c){c.addEventListener("click",function(){t.forEach(function(t){t.classList.remove("active")}),e.forEach(function(t){t.classList.remove("active")}),c.classList.add("active"),document.getElementById(c.dataset.target).classList.add("active")})})});